params.script:
var reason = String($ivr.getObject("reason") || "");
var classification = String($ivr.getObject("classification") || "問い合わせ");
if (reason.length > 0) {
    $runner.setResult("問い合わせ");
} else {
    $runner.setResult(classification);
}

var d = new Date();
var day = d.getDay();
if (day === 0 || day === 6) {
    $runner.setResult("土日");
} else {
    $runner.setResult("平日");
}
